def gen(rng, size):
    b = rng.randint(0, max(0, min(size, 60)))
    used = set()
    blocked = []
    while len(blocked) < b:
        c = (rng.randint(0, 30), rng.randint(0, 30))
        if c not in used:
            used.add(c)
            blocked.append([c[0], c[1]])
    def free():
        while True:
            c = (rng.randint(0, 40), rng.randint(0, 40))
            if c not in used:
                return c
    s = free()
    used.add(s)
    t = free()
    return [blocked, [s[0], s[1]], [t[0], t[1]]]

