class Solution:
    def isEscapePossible(self, blocked, source, target):
        # Coordinate-compression flood fill: an independent exact method.
        xs = sorted(set([0, 999999, source[0], target[0]] + [b[0] for b in blocked] + [c for b in blocked for c in (b[0]-1, b[0]+1)] + [source[0]-1, source[0]+1, target[0]-1, target[0]+1]))
        ys = sorted(set([0, 999999, source[1], target[1]] + [b[1] for b in blocked] + [c for b in blocked for c in (b[1]-1, b[1]+1)] + [source[1]-1, source[1]+1, target[1]-1, target[1]+1]))
        xs = [x for x in xs if 0 <= x <= 999999]
        ys = [y for y in ys if 0 <= y <= 999999]
        xi = {x: i for i, x in enumerate(xs)}
        yi = {y: i for i, y in enumerate(ys)}
        W, H = len(xs), len(ys)
        blockset = set((xi[b[0]], yi[b[1]]) for b in blocked)
        sx, sy = xi[source[0]], yi[source[1]]
        tx, ty = xi[target[0]], yi[target[1]]
        from collections import deque
        seen = {(sx, sy)}
        dq = deque([(sx, sy)])
        while dq:
            x, y = dq.popleft()
            if (x, y) == (tx, ty):
                return True
            for nx, ny in ((x+1,y),(x-1,y),(x,y+1),(x,y-1)):
                if 0 <= nx < W and 0 <= ny < H and (nx, ny) not in blockset and (nx, ny) not in seen:
                    seen.add((nx, ny))
                    dq.append((nx, ny))
        return False

