class Solution:
    def isEscapePossible(self, blocked, source, target):
        LIMIT = 1000000
        block = set(map(tuple, blocked))
        bound = len(blocked) * (len(blocked) - 1) // 2 + 5
        from collections import deque
        def bfs(start, goal):
            seen = {tuple(start)}
            dq = deque([tuple(start)])
            goal = tuple(goal)
            while dq:
                if len(seen) > bound:
                    return True
                x, y = dq.popleft()
                if (x, y) == goal:
                    return True
                for nx, ny in ((x+1,y),(x-1,y),(x,y+1),(x,y-1)):
                    if 0 <= nx < LIMIT and 0 <= ny < LIMIT and (nx, ny) not in block and (nx, ny) not in seen:
                        seen.add((nx, ny))
                        dq.append((nx, ny))
            return False
        return bfs(source, target) and bfs(target, source)

