var isEscapePossible = function(blocked, source, target) {
    const LIMIT = 1000000;
    const block = new Set(blocked.map(b => b[0] * LIMIT + b[1]));
    const bound = Math.floor(blocked.length * (blocked.length - 1) / 2) + 5;
    const bfs = (start, goal) => {
        const seen = new Set([start[0] * LIMIT + start[1]]);
        let queue = [start];
        const gk = goal[0] * LIMIT + goal[1];
        while (queue.length) {
            if (seen.size > bound) return true;
            const next = [];
            for (const [x, y] of queue) {
                if (x * LIMIT + y === gk) return true;
                for (const [nx, ny] of [[x+1,y],[x-1,y],[x,y+1],[x,y-1]]) {
                    if (nx < 0 || ny < 0 || nx >= LIMIT || ny >= LIMIT) continue;
                    const k = nx * LIMIT + ny;
                    if (block.has(k) || seen.has(k)) continue;
                    seen.add(k);
                    next.push([nx, ny]);
                }
            }
            queue = next;
        }
        return false;
    };
    return bfs(source, target) && bfs(target, source);
};
